const files = ["types.ts", "schema.ts", "service.ts"]
function gitShow(file) {
  const sourcePath = "origin/stream/os:packages/os/scripts/lib/code-call/" + file
  const proc = Bun.spawnSync({ cmd: ["git", "show", sourcePath], stdout: "pipe", stderr: "pipe" })
  if (proc.exitCode !== 0) throw new Error(new TextDecoder().decode(proc.stderr))
  return new TextDecoder().decode(proc.stdout)
}
const results = []
for (const file of files) {
  const source = gitShow(file)
  const target = await Bun.file("packages/workspace/scripts/lib/code-call/" + file).text()
  results.push({ file, exactMatch: source === target, sourceChars: source.length, targetChars: target.length })
}
const ok = results.every((result) => result.exactMatch)
